content:
{
  "schemaVersion": 3,
  "judgeId": "judge_2",
  "batchIndex": 3,
  "comparisons": [
    {
      "leftId": "c4_rock_pool_tides",
      "rightId": "dt_01_concept_01",
      "winnerId": "c4_rock_pool_tides",
      "reason": "C4 thể hiện rõ chất nam tần làm giàu bằng tay nghề khai thác trực tiếp tài nguyên biển (nhum, ốc) với cơ chế thủy triều và rạn đá rất đặc thù. Concept 01 thiên về ẩm thực đơn thuần, chưa làm bật lên được quá trình thị trường hóa và các khó khăn của nghề biển như C4."
    },
    {
      "leftId": "c4_rock_pool_tides",
      "rightId": "dt_01_concept_02",
      "winnerId": "dt_01_concept_02",
      "reason": "Concept 02 khai thác sâu vào ngành mắm - một trọng tâm của domain opportunity. Việc dùng kiến thức vi sinh để cứu mẻ mắm hỏng và lộ trình xây dựng thương hiệu mắm nhỉ 30 chương có chiều sâu kinh tế và tính chuyên môn cao hơn việc nhặt ốc ở C4."
    },
    {
      "leftId": "c4_rock_pool_tides",
      "rightId": "dt_01_concept_03",
      "winnerId": "c4_rock_pool_tides",
      "reason": "C4 có tính agency cao hơn khi nhân vật chính chủ động đối mặt với sóng gió bãi đá để kiếm tiền trả nợ ngay chương 3. Concept 03 thiên về hậu cần (vá lưới), dù kỹ thuật tốt nhưng nhịp độ tạo ra thành quả kinh tế trực tiếp từ biển không mạnh mẽ bằng C4."
    },
    {
      "leftId": "c4_rock_pool_tides",
      "rightId": "dt_01_concept_04",
      "winnerId": "c4_rock_pool_tides",
      "reason": "C4 tạo ra dòng tiền và bữa cơm tốt hơn (cháo nhum, tiền trả nợ) ngay lập tức. Concept 04 về rong biển gặp rào cản định kiến lớn và nhịp độ chậm hơn trong việc biến 'cỏ rác' thành hàng hóa có giá trị cao ở giai đoạn đầu."
    },
    {
      "leftId": "c4_rock_pool_tides",
      "rightId": "dt_01_concept_05",
      "winnerId": "dt_01_concept_05",
      "reason": "Concept 05 giải quyết 'điểm nghẽn' lớn nhất của huyện biển cuối thập niên 80 là bảo quản lạnh. Cơ chế hầm đá lót trấu/xơ dừa rất thực tế, causal cost rõ ràng và có tiềm năng mở rộng quy mô thành nhà máy nước đá, khớp hoàn hảo với yêu cầu thị trường hóa."
    },
    {
      "leftId": "c4_rock_pool_tides",
      "rightId": "dt_01_concept_06",
      "winnerId": "c4_rock_pool_tides",
      "reason": "C4 tập trung vào việc nhận diện và khai thác sản lượng hải sản bị đánh giá thấp, đúng với yêu cầu về mẻ hàng đầu tiên. Concept 06 tập trung vào cải tạo công cụ (thuyền), dù hay nhưng chưa tạo ra sự 'khoái hoạt' từ việc trực tiếp thu hoạch lộc biển như C4."
    },
    {
      "leftId": "c4_rock_pool_tides",
      "rightId": "dt_01_concept_07",
      "winnerId": "c4_rock_pool_tides",
      "reason": "C4 mang lại cảm giác mạo hiểm và thành quả hữu hình từ bãi đá nguy hiểm. Concept 07 về ruốc sấy thiên về marketing và quy trình phơi sấy tĩnh, thiếu đi sự chủ động chinh phục thiên nhiên biển cả mà độc giả nam tần thường ưa chuộng."
    },
    {
      "leftId": "c4_rock_pool_tides",
      "rightId": "dt_01_concept_08",
      "winnerId": "c4_rock_pool_tides",
      "reason": "C4 có vòng lặp thưởng cá nhân và gia đình rất rõ nét (trả nợ, bồi bổ cho con). Concept 08 mang tính cộng đồng và 'gọi sò' hơi sớm, dễ làm loãng nỗ lực cá nhân của nhân vật chính trong việc làm giàu bằng tay nghề riêng."
    },
    {
      "leftId": "c4_rock_pool_tides",
      "rightId": "dt_01_concept_09",
      "winnerId": "c4_rock_pool_tides",
      "reason": "C4 khai thác hải sản giá trị cao (nhum gạch) cho nhà hàng, tạo ra sự bứt phá tài chính nhanh. Concept 09 về muối là mảng hay nhưng nhịp độ kinh tế chậm và phụ thuộc quá nhiều vào việc sàng lọc thủ công, khó tạo ra sự khoái hoạt sớm."
    },
    {
      "leftId": "c4_rock_pool_tides",
      "rightId": "dt_01_concept_10",
      "winnerId": "c4_rock_pool_tides",
      "reason": "C4 bám sát thực tế kinh tế những năm 1988. Concept 10 đưa yếu tố du lịch trải nghiệm vào thời kỳ này là quá sớm và không phù hợp với tâm thế độc giả thích làm giàu bằng lao động sản xuất và tay nghề biển."
    },
    {
      "leftId": "c5_shrimp_paste",
      "rightId": "c6_handline_bait",
      "winnerId": "c6_handline_bait",
      "reason": "C6 tạo ra sự kịch tính cao độ với kỹ năng câu cá mú hang sâu bằng tay và mồi đặc chế. Phần thưởng mua được máy nổ cũ ở chương 3 là một bước tiến thiết bị rất 'nam tần', vượt trội hơn việc bán mẻ mắm tép đổi gạo ở C5."
    },
    {
      "leftId": "c5_shrimp_paste",
      "rightId": "c7_live_seafood_transport",
      "winnerId": "c7_live_seafood_transport",
      "reason": "C7 có cơ chế cơ khí ứng dụng (bơm xe đạp làm sục khí) rất sáng tạo và thực tế với điều kiện thiếu thốn. Causal cost (đạp xe 20km vừa bơm khí) tạo ra sự đồng cảm và agency mạnh mẽ cho nhân vật chính."
    },
    {
      "leftId": "c5_shrimp_paste",
      "rightId": "c8_light_luring_squid",
      "winnerId": "c8_light_luring_squid",
      "reason": "C8 khai thác đúng điểm nghẽn về kỹ thuật (ánh sáng) và chi phí (dầu hỏa) thời bấy giờ. Việc gò chóa đèn để tối ưu hóa ánh sáng là một cơ chế tay nghề thông minh, dẫn đến mẻ mực bội thu rất thuyết phục."
    },
    {
      "leftId": "c5_shrimp_paste",
      "rightId": "c9_oyster_spat_poles",
      "winnerId": "c9_oyster_spat_poles",
      "reason": "C9 kết hợp tốt giữa sinh kế ngắn hạn (bắt cá đối quanh cọc) và đầu tư dài hạn (nuôi hàu). Cơ chế dùng lốp xe cũ làm giá thể rất thực tế và thể hiện tư duy tận dụng phế liệu của thời đại."
    },
    {
      "leftId": "c5_shrimp_paste",
      "rightId": "c10_net_modifications",
      "winnerId": "c10_net_modifications",
      "reason": "C10 có chuyên môn sâu về thủy động lực học áp dụng vào vá lưới, biến một công việc bị coi khinh thành nghệ thuật độ thiết bị. Điều này tạo ra vị thế độc bản cho nhân vật chính trong làng chài tốt hơn C5."
    },
    {
      "leftId": "c5_shrimp_paste",
      "rightId": "dt_01_concept_01",
      "winnerId": "c5_shrimp_paste",
      "reason": "C5 có quy trình sản xuất và quản lý dòng vốn (xoay vòng mẻ mắm 10 ngày) chặt chẽ hơn. Concept 01 thiên về nấu nướng đơn lẻ, chưa thể hiện rõ quy mô sản xuất và tính thị trường hóa như cách C5 gom moi biển làm mắm."
    },
    {
      "leftId": "c5_shrimp_paste",
      "rightId": "dt_01_concept_02",
      "winnerId": "dt_01_concept_02",
      "reason": "Concept 02 có nền tảng kiến thức vi sinh vững chắc và lộ trình phát triển từ cứu mẻ mắm hỏng đến xây dựng thương hiệu nước mắm nhỉ cao cấp rất bài bản, khớp sâu với domain opportunity về mắm và muối."
    },
    {
      "leftId": "c5_shrimp_paste",
      "rightId": "dt_01_concept_03",
      "winnerId": "dt_01_concept_03",
      "reason": "Concept 03 xây dựng mâu thuẫn gia đình (cha mắc nợ vì lưới rách) và cách giải quyết bằng kỹ thuật đan lưới mắt cáo rất cụ thể. Điều này tạo ra động lực nhân vật và agency mạnh hơn so với việc làm mắm tép ở C5."
    },
    {
      "leftId": "c5_shrimp_paste",
      "rightId": "dt_01_concept_04",
      "winnerId": "c5_shrimp_paste",
      "reason": "C5 thực tế hơn về mặt thị trường tiêu thụ tại Việt Nam cuối thập niên 80 (mắm tép chưng thịt là món đưa cơm phổ biến). Concept 04 về rong biển khó tạo ra dòng tiền ổn định và sự chấp nhận rộng rãi của người dân trong bối cảnh đói kém."
    },
    {
      "leftId": "c5_shrimp_paste",
      "rightId": "dt_01_concept_05",
      "winnerId": "dt_01_concept_05",
      "reason": "Concept 05 giải quyết vấn đề bảo quản - yếu tố sống còn để nâng giá trị hải sản. Cơ chế giữ lạnh thủ công bằng vật liệu tự nhiên là một điểm sáng về tư duy kỹ thuật trong điều kiện thiếu thốn, có sức nặng hơn việc làm mắm xổi."
    }
  ]
}
